Use ASP.NET Core's **`WebApplicationFactory<T>`** — it hosts your app in-memory and gives you an `HttpClient` that talks to it with no real network socket.

### Setup

```bash
dotnet add package Microsoft.AspNetCore.Mvc.Testing
```

### Example test class

```csharp
using Microsoft.AspNetCore.Mvc.Testing;
using System.Net.Http.Json;
using System.Text.Json;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2025-03-26",
            body.GetProperty("result")
                .GetProperty("protocolVersion")
                .GetString());
    }

    [Fact]
    public async Task ToolsCall_ReturnsExpectedResult()
    {
        // 1. Initialize first (stateful session)
        var init = new { jsonrpc = "2.0", id = 1, method = "initialize",
            @params = new { protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test", version = "1.0" } } };

        var initResp = await _client.PostAsJsonAsync("/mcp", init);
        // Grab session ID from Mcp-Session-Id header if your server uses it
        var sessionId = initResp.Headers
            .GetValues("Mcp-Session-Id").FirstOrDefault();

        // 2. Call a tool
        var toolCall = new { jsonrpc = "2.0", id = 2, method = "tools/call",
            @params = new { name = "echo",
                arguments = new { message = "hello" } } };

        var req = new HttpRequestMessage(HttpMethod.Post, "/mcp");
        req.Content = JsonContent.Create(toolCall);
        if (sessionId != null)
            req.Headers.Add("Mcp-Session-Id", sessionId);

        var resp = await _client.SendAsync(req);
        resp.EnsureSuccessStatusCode();

        var body = await resp.Content.ReadFromJsonAsync<JsonElement>();
        var text = body.GetProperty("result")
            .GetProperty("content")[0]
            .GetProperty("text")
            .GetString();

        Assert.Equal("hello", text);
    }
}
```

### Key points

| Concern | Approach |
|---|---|
| **No real server** | `WebApplicationFactory` hosts in-process |
| **Session state** | Forward the `Mcp-Session-Id` header between requests |
| **SSE streams** | Use `HttpCompletionOption.ResponseHeadersRead` + read the stream line-by-line for SSE-based responses |
| **`Program` visibility** | Add `<InternalsVisibleTo Include="YourTestProject" />` or a partial class `public partial class Program { }` |

### Reading SSE responses (if your server uses streaming)

```csharp
var req = new HttpRequestMessage(HttpMethod.Post, "/mcp") { Content = ... };
req.Headers.Accept.Add(new("text/event-stream"));

var resp = await _client.SendAsync(req,
    HttpCompletionOption.ResponseHeadersRead);

using var stream = await resp.Content.ReadAsStreamAsync();
using var reader = new StreamReader(stream);

while (await reader.ReadLineAsync() is { } line)
{
    if (line.StartsWith("data: "))
    {
        var json = JsonDocument.Parse(line[6..]);
        // assert on each event
    }
}
```

This gives you full protocol-level coverage (JSON-RPC framing, headers, SSE) with fast, deterministic, in-process tests.
